css:
/* setting the Header color depending on the theme */
.fd-form h1 {
    color: var(--fd-primary) !important;
}

/* changing the styling of the Tab container when theme changes*/

/****** THEME 1 ******/

.fd-form .nav-tabs .nav-link:hover {
    color: #333;
    background-color: #D7E1E5 !important;
    border-color: #D7E1E5 #D7E1E5 #006699 !important;
}

.fd-form .nav-tabs .nav-link.active,
.fd-form .nav-tabs .nav-link:focus {
    color: #333;
    border-color: #006699 #006699 #fff5e7 !important;
}

.fd-form .nav-link {
    color: #006699;
}

.fd-form .tabset:not(.fd-form .tabset--nowrap).tabs-top>.nav-tabs>.nav-item::before {
    border-bottom-color: #006699 !important;
}

.fd-form .nav-tabs,
.fd-form .nav-tabs:hover {
    border-bottom-color: #006699 !important;
}

/****** THEME 2 ******/


.fd-form[theme='2ecd4ce5facf19377e01db09718441c2'] .nav-tabs .nav-link:hover {
    color: #333;
    background-color: #D7E1E5 !important;
    border-color: #D7E1E5 #D7E1E5 #006699 !important;
    border-radius: 10px !important;
}

.fd-form[theme='2ecd4ce5facf19377e01db09718441c2'] .nav-tabs .nav-link.active,
.fd-form[theme='2ecd4ce5facf19377e01db09718441c2'] .nav-tabs .nav-link:focus {
    border-color: #006699 #006699 #fff5e7 !important;
    background-color: #6658EA !important;
    color: white !important;
    border-radius: 10px !important;
}


.fd-form[theme='2ecd4ce5facf19377e01db09718441c2'] .nav-link {
    color: #006699;
}

.fd-form[theme='2ecd4ce5facf19377e01db09718441c2'] .nav-tabs,
.fd-form[theme='2ecd4ce5facf19377e01db09718441c2'] .nav-tabs:hover {
    border-bottom-color: #006699 !important;
}

/****** THEME 3 ******/

.fd-form[theme='801be8983d8d8103fc06734df046c645'] h1 {
    font-weight: 1000;
}

.fd-form[theme='801be8983d8d8103fc06734df046c645'] .nav-tabs .nav-link:hover {
    color: #333;
    background-color: transparent !important;
    border-bottom: 5px solid #9C27B0 !important;
}

.fd-form[theme='801be8983d8d8103fc06734df046c645'] .nav-tabs .nav-link.active,
.fd-form[theme='801be8983d8d8103fc06734df046c645'] .nav-tabs .nav-link:focus {
    color: #333;
    border-bottom: 5px solid #9C27B0 !important;
}


.fd-form[theme='801be8983d8d8103fc06734df046c645'] .nav-link {
    color: #333;
}

.fd-form[theme='801be8983d8d8103fc06734df046c645'] .nav-tabs,
.fd-form[theme='801be8983d8d8103fc06734df046c645'] .nav-tabs:hover {
    border-bottom-color: #9C27B0 !important;
}

/****** THEME 4 ******/

.fd-form[theme='3ea78ff0c01ec9657c0230a11b1997e1'] h1 {
    font-weight: 1000;
}

.fd-form[theme='3ea78ff0c01ec9657c0230a11b1997e1'] .nav-tabs .nav-link:hover {
    color: #f5a637;
    background-color: #D7E1E5;
    border: none;
}

.fd-form[theme='3ea78ff0c01ec9657c0230a11b1997e1'] .nav-tabs .nav-link.active,
